// Get AI output
const inputData = $input.first().json;
let aiOutput = inputData.output || inputData.text || '';

if (typeof aiOutput !== 'string') {
  aiOutput = JSON.stringify(aiOutput);
}

// Clean up
aiOutput = aiOutput.trim().replace(/```json\s*/gi, '').replace(/```\s*/g, '');

// Try to parse JSON
let parsed;
try {
  parsed = JSON.parse(aiOutput);
} catch (e1) {
  const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[0]);
    } catch (e2) {
      return [{
        json: {
          Date: new Date().toISOString().split('T')[0],
          Salesperson: 'PARSE_ERROR',
          Items_Sold: 0,
          Price_Per_Item: 0,
          Total_Revenue: 0,
          Top_Performer: '',
          Insights: 'Error: ' + e2.message + ' | Raw: ' + aiOutput.substring(0, 150)
        }
      }];
    }
  } else {
    return [{
      json: {
        Date: new Date().toISOString().split('T')[0],
        Salesperson: 'NO_JSON',
        Items_Sold: 0,
        Price_Per_Item: 0,
        Total_Revenue: 0,
        Top_Performer: '',
        Insights: aiOutput.substring(0, 200)
      }
    }];
  }
}

// Accept both "rows" and "records" field names
const rowsArray = parsed.rows || parsed.records || parsed.data || [];

if (!Array.isArray(rowsArray) || rowsArray.length === 0) {
  return [{
    json: {
      Date: new Date().toISOString().split('T')[0],
      Salesperson: 'NO_ROWS',
      Items_Sold: 0,
      Price_Per_Item: 0,
      Total_Revenue: 0,
      Top_Performer: '',
      Insights: 'AI response had no rows: ' + JSON.stringify(parsed).substring(0, 200)
    }
  }];
}

const today = new Date().toISOString().split('T')[0];
const topPerformer = parsed.top_performer || parsed.topPerformer || '';
const insights = parsed.insights || '';

// Map each row, accepting multiple field name variations
const items = rowsArray.map(row => {
  const name = row.salesperson || row.name || 'Unknown';
  const items_sold = Number(row.items_sold || row.itemsSold || row.items || 0);
  const price = Number(row.price_per_item || row.pricePerItem || row.price || 0);
  const total = Number(row.total_revenue || row.totalSales || row.totalRevenue || row.total || (items_sold * price));

  return {
    json: {
      Date: today,
      Salesperson: String(name),
      Items_Sold: items_sold,
      Price_Per_Item: price,
      Total_Revenue: total,
      Top_Performer: String(topPerformer),
      Insights: String(insights)
    }
  };
});

return items;

const rows = $input.all().map(item => item.json);

const pick = (obj, keys, fallback = '') => {
  for (const k of keys) {
    if (obj[k] !== undefined && obj[k] !== null) return obj[k];
  }
  return fallback;
};

const data = rows.map(r => ({
  salesperson: String(pick(r, ['Salesperson', 'salesperson'])),
  itemsSold: Number(pick(r, ['Items Sold', 'items_sold', 'itemsSold'], 0)),
  pricePerItem: Number(pick(r, ['Price Per Item', 'price_per_item', 'pricePerItem'], 0)),
  totalRevenue: Number(pick(r, ['Total Revenue', 'total_revenue', 'totalSales'], 0)),
}));

const labels = data.map(d => d.salesperson);
const revenue = data.map(d => d.totalRevenue);
const totalSales = revenue.reduce((a, b) => a + b, 0);
const top = data.reduce((best, cur) => (cur.totalRevenue > best.totalRevenue ? cur : best), data[0]);

const colors = ['#4F46E5', '#06B6D4', '#22C55E', '#F59E0B', '#EF4444', '#8B5CF6'];

const barConfig = {
  type: 'bar',
  data: {
    labels,
    datasets: [{
      label: 'Revenue ($)',
      data: revenue,
      backgroundColor: colors,
      borderRadius: 8,
    }]
  },
  options: {
    plugins: {
      legend: { display: false },
      title: { display: true, text: 'Revenue by Salesperson', color: '#111827', font: { size: 18 } }
    },
    scales: {
      y: { beginAtZero: true, ticks: { color: '#374151' } },
      x: { ticks: { color: '#374151' } }
    }
  }
};

const pieConfig = {
  type: 'pie',
  data: {
    labels,
    datasets: [{ data: revenue, backgroundColor: colors }]
  },
  options: {
    plugins: {
      title: { display: true, text: 'Revenue Share (%)', color: '#111827', font: { size: 18 } },
      legend: { position: 'bottom' }
    }
  }
};

const lineConfig = {
  type: 'line',
  data: {
    labels,
    datasets: [{
      label: 'Revenue Trend',
      data: revenue,
      borderColor: '#4F46E5',
      backgroundColor: 'rgba(79,70,229,0.2)',
      fill: true,
      tension: 0.35,
      pointRadius: 5
    }]
  },
  options: {
    plugins: {
      title: { display: true, text: 'Revenue Trend Line', color: '#111827', font: { size: 18 } }
    },
    scales: {
      y: { beginAtZero: true, ticks: { color: '#374151' } },
      x: { ticks: { color: '#374151' } }
    }
  }
};

const base = 'https://quickchart.io/chart';
const chartUrl = (cfg, w = 900, h = 500) =>
  `${base}?w=${w}&h=${h}&bkg=white&c=${encodeURIComponent(JSON.stringify(cfg))}`;

const barUrl = chartUrl(barConfig);
const pieUrl = chartUrl(pieConfig, 700, 700);
const lineUrl = chartUrl(lineConfig);

const summary = data.map(d => `- ${d.salesperson}: ${d.itemsSold} x $${d.pricePerItem} = $${d.totalRevenue}`).join('\n');

return [{
  json: {
    output:
`Saved ${data.length} rows to Google Sheets.

Summary:
${summary}

Top seller: ${top.salesperson} ($${top.totalRevenue})
Total sales: $${totalSales}

Bar chart: ${barUrl}
Pie chart: ${pieUrl}
Line chart: ${lineUrl}`,
    barChartUrl: barUrl,
    pieChartUrl: pieUrl,
    lineChartUrl: lineUrl,
    totalSales,
    topSeller: top.salesperson
  }
}];
